typedef long long int LL;
LL countArrays(string s,int C,int K){

    int N=s.length();
    LL P=1;
    vector<LL> dp(N);

    for(int i=0;i<K;i++)P*=10;
    for(int i=0;i<N;i++){
        LL count=0;
        LL x=0,p10=1;
        for(int j=i;j>=max(0,i-9);j--){
            x+=(LL)p10*(s[j]-'0');
            p10*=10;
            if(j<i && s[j]=='0') continue;// leading zero
            if(x>(LL)C) break;// too large number

            count=(count+(j==0?1:dp[j-1]))%P;
        }
        dp[i]=count;
    }
    return dp[N-1];
}

int main(void){

    cout<<countArrays("1234567",1234567,9)<<endl;
    cout<<countArrays("1234567",500,9)<<endl;
    cout<<countArrays("5190620079",500,5)<<endl;
    cout<<countArrays("64310297034100643820003649",4530,5)<<endl;
    return 0;
}
